import { parseAcceptanceCriteria } from './src/lib/ac-parser.ts';
import { performScopeAssessment, formatScopeAssessment, convertSettingsToConfig } from './src/lib/scope/index.ts';
import { getSettings } from './src/lib/settings.ts';

const issueBody = \`## Acceptance Criteria

- [ ] bin/cli.ts lazy-loads serve.ts via dynamic import() inside the .action() handler
- [ ] npx sequant run, npx sequant doctor, npx sequant init work without @modelcontextprotocol/sdk installed
- [ ] npx sequant serve gives a clear error if SDK is not installed (not a cryptic import failure)
- [ ] npm run build passes without the SDK installed (type-only imports need conditional handling)
- [ ] Tests pass without the SDK installed (MCP tests can be skipped with a guard)
- [ ] doctor MCP health check continues to work (already uses dynamic import — verify)\`;

const issueTitle = 'fix: lazy-load MCP SDK to prevent build failures when SDK is not installed';

(async () => {
  const settings = await getSettings();
  const config = convertSettingsToConfig(settings.scopeAssessment);
  const criteria = parseAcceptanceCriteria(issueBody);
  const assessment = performScopeAssessment(criteria, issueBody, issueTitle, config);
  console.log(formatScopeAssessment(assessment));
